{
  "preconditions": [
    "a must be a hashable type",
    "b must be a hashable type"
  ],
  "postconditions": [
    "a == b if and only if eq(a, b) returns True",
    "not a == b if and only if eq(a, b) returns False"
  ],
  "edge_cases": [
    "eq(a, a) returns True for any a",
    "eq(a, b) returns False if a and b are of different types"
  ]
}

